revision.text:
/* {{pp-template}} */
@media all and (max-width: 720px) {
	.mod-gallery {
		width: 100% !important;
	}
}

.mod-gallery {
	display: table;
}

.mod-gallery-default {
	background: transparent;
	margin-top: 0.3em;
}

.mod-gallery-center {
	margin-left: auto;
	margin-right: auto;
}

.mod-gallery-left {
	float: left;
}

.mod-gallery-right {
	float: right;
}

.mod-gallery-none {
	float: none;
}

.mod-gallery-collapsible {
	width: 100%;
}

.mod-gallery .title,
.mod-gallery .main,
.mod-gallery .footer {
	display: table-row;
}

.mod-gallery .title > div {
	display: table-cell;
	padding: 0.2em 0 0.6em 1.6em;
	text-align: center;
	font-weight: bold;
}

.mod-gallery .main > div {
	display: table-cell;
}

.mod-gallery .gallery {
	line-height: 1.35em;
}

.mod-gallery .footer > div {
	display: table-cell;
	padding: 0.2em 0 0.6em 1.6em;
	text-align: right;
	font-size: 80%;
	line-height: 1em;
}

.mod-gallery .title > div *,
.mod-gallery .footer > div * {
	overflow: visible;
}

.mod-gallery .gallerybox img {
	background: none !important;
}

.mod-gallery .bordered-images .thumb img {
	border: solid #eaecf0 1px;
}

.mod-gallery .whitebg .thumb {
	background: #fff !important;
}

/* {{pp-template}} */
@media all and (max-width: 720px) {
	.mod-gallery {
		width: 100% !important;
	}
}

.mod-gallery {
	display: table;
}

.mod-gallery-default {
	background: transparent;
	margin-top: 0.3em;
}

.mod-gallery-center {
	margin-left: auto;
	margin-right: auto;
}

.mod-gallery-left {
